```go
package agent

import (
    "strings"
    "time"
)

// Parser extracts AgentState from raw terminal output
type Parser interface {
    Parse(output string) (*AgentState, error)
    DetectAgentType(output string) AgentType
}

// ParserConfig customizes parser behavior
type ParserConfig struct {
    ContextLowThreshold float64 // Flag if below this % (default: 20)
    SampleLength        int     // Chars to keep in RawSample (default: 500)
}

// DefaultParserConfig returns sensible defaults
func DefaultParserConfig() ParserConfig {
    return ParserConfig{
        ContextLowThreshold: 20.0,
        SampleLength:        500,
    }
}

type parserImpl struct {
    config ParserConfig
}

// NewParser creates parser with default config
func NewParser() Parser {
    return &parserImpl{config: DefaultParserConfig()}
}

// NewParserWithConfig creates parser with custom config
func NewParserWithConfig(cfg ParserConfig) Parser {
    return &parserImpl{config: cfg}
}

func (p *parserImpl) Parse(output string) (*AgentState, error) {
    state := &AgentState{
        ParsedAt: time.Now().UTC(),
    }

    // Step 1: Detect agent type
    state.Type = p.DetectAgentType(output)

    // Step 2: Extract metrics based on agent type
    p.extractMetrics(output, state)

    // Step 3: Detect state flags
    p.detectStateFlags(output, state)

    // Step 4: Calculate confidence
    state.Confidence = p.calculateConfidence(state)

    // Step 5: Keep sample for debugging
    if len(output) > p.config.SampleLength {
        state.RawSample = output[len(output)-p.config.SampleLength:]
    } else {
        state.RawSample = output
    }

    return state, nil
}

func (p *parserImpl) DetectAgentType(output string) AgentType {
    // Check headers/signatures in priority order
    if ccHeaderPattern.MatchString(output) {
        return AgentTypeClaudeCode
    }
    if codContextPattern.MatchString(output) || codHeaderPattern.MatchString(output) {
        return AgentTypeCodex
    }
    if gmiHeaderPattern.MatchString(output) || gmiYoloPattern.MatchString(output) {
        return AgentTypeGemini
    }

    // Fallback: use pattern frequency
    return p.detectByPatternFrequency(output)
}

func (p *parserImpl) extractMetrics(output string, state *AgentState) {
    switch state.Type {
    case AgentTypeCodex:
        // Codex gives us explicit percentage - most valuable!
        if pct := extractFloat(codContextPattern, output); pct != nil {
            state.ContextRemaining = pct
            if *pct < p.config.ContextLowThreshold {
                state.IsContextLow = true
            }
        }
        // Also extract token count if present
        // (useful for tracking but less actionable)

    case AgentTypeGemini:
        // Gemini shows memory, less useful but track it
        if mb := extractFloat(gmiMemoryPattern, output); mb != nil {
            state.MemoryMB = mb
        }

    case AgentTypeClaudeCode:
        // Claude doesnt give explicit metrics
        // We rely on warning messages instead
        if matchAny(output, ccContextWarnings) {
            state.IsContextLow = true
        }
    }
}

func (p *parserImpl) detectStateFlags(output string, state *AgentState) {
    // Rate limit detection (highest priority)
    state.IsRateLimited = p.detectRateLimit(output, state.Type)
    if state.IsRateLimited {
        state.LimitIndicators = p.collectLimitIndicators(output, state.Type)
    }

    // Working detection
    state.IsWorking = p.detectWorking(output, state.Type)
    if state.IsWorking {
        state.WorkIndicators = p.collectWorkIndicators(output, state.Type)
    }

    // Idle detection (only if not working and not rate limited)
    if !state.IsWorking && !state.IsRateLimited {
        state.IsIdle = p.detectIdle(output, state.Type)
    }

    // Error detection
    state.IsInError = p.detectError(output, state.Type)
}

func (p *parserImpl) detectRateLimit(output string, agentType AgentType) bool {
    switch agentType {
    case AgentTypeClaudeCode:
        return matchAny(output, ccRateLimitPatterns)
    case AgentTypeCodex:
        return matchAny(output, codRateLimitPatterns)
    case AgentTypeGemini:
        return matchAny(output, gmiRateLimitPatterns)
    }
    return false
}

func (p *parserImpl) detectWorking(output string, agentType AgentType) bool {
    // Check for recent output indicators
    // Focus on the LAST portion of output (recent activity)
    recentOutput := getLastNLines(output, 20)

    switch agentType {
    case AgentTypeClaudeCode:
        return matchAny(recentOutput, ccWorkingPatterns)
    case AgentTypeCodex:
        return matchAny(recentOutput, codWorkingPatterns)
    case AgentTypeGemini:
        return matchAny(recentOutput, gmiWorkingPatterns)
    }
    return false
}

func (p *parserImpl) detectIdle(output string, agentType AgentType) bool {
    // Check if last lines look like a prompt
    lastLines := getLastNLines(output, 5)

    switch agentType {
    case AgentTypeClaudeCode:
        return matchAnyRegex(lastLines, ccIdlePatterns)
    case AgentTypeCodex:
        return matchAnyRegex(lastLines, codIdlePatterns)
    case AgentTypeGemini:
        // Gemini is trickier - check for lack of activity
        return !matchAny(lastLines, gmiWorkingPatterns)
    }
    return false
}

func (p *parserImpl) calculateConfidence(state *AgentState) float64 {
    confidence := 0.5 // Base confidence

    // Boost for explicit metrics
    if state.ContextRemaining != nil {
        confidence += 0.25 // Codex percentage is reliable
    }

    // Boost for clear indicators
    if len(state.WorkIndicators) > 0 {
        confidence += 0.1 * float64(min(len(state.WorkIndicators), 3))
    }
    if len(state.LimitIndicators) > 0 {
        confidence += 0.2 // Rate limits are unambiguous
    }

    // Penalty for unknown type
    if state.Type == AgentTypeUnknown {
        confidence -= 0.3
    }

    // Clamp to [0, 1]
    if confidence > 1.0 {
        confidence = 1.0
    }
    if confidence < 0.0 {
        confidence = 0.0
    }

    return confidence
}

// Helper: get last N lines of text
func getLastNLines(text string, n int) string {
    lines := strings.Split(text, "\n")
    if len(lines) <= n {
        return text
    }
    return strings.Join(lines[len(lines)-n:], "\n")
}
```

### Edge Cases to Handle

1. **Empty output** - Return Unknown type with low confidence
2. **Mixed agent output** - Can happen during restart; use most recent patterns
3. **ANSI escape codes** - Strip before pattern matching
4. **Very long output** - Only analyze last N lines for efficiency

